132	// CheckProcessRunning verifies that a named process is currently running on the host.
133	// Uses exact process-name matching (pgrep -x on Unix, CSV-parsed tasklist on Windows).
134	// Bounded by a 2s timeout to prevent hangs.
135	func CheckProcessRunning(name string) AssertionResult {
136		if name == "" {
137			return AssertionResult{Type: "process_running", Expected: name, Actual: "empty name", Passed: false}
138		}
139		ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
140		defer cancel()
141		if runtime.GOOS == "windows" {
142			filter := fmt.Sprintf("IMAGENAME eq %s", name)
143			out, err := exec.CommandContext(ctx, "tasklist", "/FI", filter, "/FO", "CSV", "/NH").Output()
144			if err != nil {
145				return AssertionResult{Type: "process_running", Expected: name, Actual: "lookup error", Passed: false}
146			}
147			if !strings.Contains(string(out), "\""+name) {
148				return AssertionResult{Type: "process_running", Expected: name, Actual: "not found", Passed: false}
149			}
150			return AssertionResult{Type: "process_running", Expected: name, Actual: "running", Passed: true}
151		}
152		out, err := exec.CommandContext(ctx, "pgrep", "-x", name).Output()
153		if err != nil {
154			if ee, ok := err.(*exec.ExitError); ok && ee.ExitCode() == 1 {
155				return AssertionResult{Type: "process_running", Expected: name, Actual: "not found", Passed: false}
156			}
157			return AssertionResult{Type: "process_running", Expected: name, Actual: "lookup error: " + err.Error(), Passed: false}
158		}
159		if len(out) == 0 {
160			return AssertionResult{Type: "process_running", Expected: name, Actual: "not found", Passed: false}
161		}
162		return AssertionResult{Type: "process_running", Expected: name, Actual: strings.TrimSpace(string(out)), Passed: true}
163	}
