194	// CheckHTTP performs an HTTP request and returns assertion results for status, body, and headers.
195	func CheckHTTP(check *schema.HTTPCheck) []AssertionResult {
196		var results []AssertionResult
197	
198		// Default method to GET
199		method := check.Method
200		if method == "" {
201			method = "GET"
202		}
203	
204		// Set timeout (default 10s)
205		timeout := 10 * time.Second
206		if check.Timeout.Duration > 0 {
207			timeout = check.Timeout.Duration
208		}
209	
210		client := &http.Client{Timeout: timeout}
211	
212		// Build request
213		var bodyReader io.Reader
214		if check.Body != "" {
215			bodyReader = strings.NewReader(check.Body)
216		}
217	
218		req, err := http.NewRequest(method, check.URL, bodyReader)
219		if err != nil {
220			return []AssertionResult{{
221				Type:     "http_request",
222				Expected: check.URL,
223				Actual:   fmt.Sprintf("invalid request: %v", err),
224				Passed:   false,
225			}}
226		}
227	
228		// Add headers
229		for k, v := range check.Headers {
230			req.Header.Set(k, v)
231		}
232	
233		// Execute request
234		resp, err := client.Do(req)
235		if err != nil {
236			return []AssertionResult{{
237				Type:     "http_request",
238				Expected: check.URL,
239				Actual:   fmt.Sprintf("request failed: %v", err),
240				Passed:   false,
241			}}
242		}
243		defer resp.Body.Close()
244	
245		// Read body
246		body, err := io.ReadAll(resp.Body)
247		if err != nil {
248			return []AssertionResult{{
249				Type:     "http_body",
250				Expected: "readable body",
251				Actual:   fmt.Sprintf("failed to read body: %v", err),
252				Passed:   false,
253			}}
254		}
255		bodyStr := string(body)
256	
257		// Check status code
258		if check.StatusCode != nil {
259			results = append(results, AssertionResult{
260				Type:     "http_status",
261				Expected: fmt.Sprintf("%d", *check.StatusCode),
262				Actual:   fmt.Sprintf("%d", resp.StatusCode),
263				Passed:   resp.StatusCode == *check.StatusCode,
264			})
265		}
266	
267		// Check body contains
268		if check.BodyContains != "" {
269			results = append(results, AssertionResult{
270				Type:     "http_body_contains",
271				Expected: check.BodyContains,
272				Actual:   bodyStr,
273				Passed:   strings.Contains(bodyStr, check.BodyContains),
274			})
275		}
276	
277		// Check body matches regex
278		if check.BodyMatches != "" {
279			matched, err := regexp.MatchString(check.BodyMatches, bodyStr)
280			if err != nil {
281				results = append(results, AssertionResult{
282					Type:     "http_body_matches",
283					Expected: check.BodyMatches,
284					Actual:   fmt.Sprintf("invalid regex: %v", err),
285					Passed:   false,
286				})
287			} else {
288				results = append(results, AssertionResult{
289					Type:     "http_body_matches",
290					Expected: check.BodyMatches,
291					Actual:   bodyStr,
292					Passed:   matched,
293				})
294			}
295		}
296	
297		// Check header contains
298		for k, v := range check.HeaderContains {
299			actual := resp.Header.Get(k)
300			results = append(results, AssertionResult{
301				Type:     "http_header_contains",
302				Expected: fmt.Sprintf("%s: %s", k, v),
303				Actual:   fmt.Sprintf("%s: %s", k, actual),
304				Passed:   strings.Contains(actual, v),
305			})
306		}
307	
308		return results
309	}
