311	// CheckSSLCert dials host:port over TLS and validates the certificate chain,
312	// expiry, and days-remaining threshold.
313	func CheckSSLCert(check *schema.SSLCertCheck) AssertionResult {
314		port := check.Port
315		if port == 0 {
316			port = 443
317		}
318		addr := fmt.Sprintf("%s:%d", check.Host, port)
319		conf := &tls.Config{
320			ServerName:         check.Host,
321			InsecureSkipVerify: check.AllowSelfSigned, //nolint:gosec -- opt-in per AllowSelfSigned flag
322		}
323		dialer := &net.Dialer{Timeout: 10 * time.Second}
324		conn, err := tls.DialWithDialer(dialer, "tcp", addr, conf)
325		if err != nil {
326			return AssertionResult{Type: "ssl_cert", Expected: addr, Actual: err.Error(), Passed: false}
327		}
328		defer conn.Close()
329		certs := conn.ConnectionState().PeerCertificates
330		if len(certs) == 0 {
331			return AssertionResult{Type: "ssl_cert", Expected: addr, Actual: "no peer certificate", Passed: false}
332		}
333		leaf := certs[0]
334		now := time.Now()
335		if now.After(leaf.NotAfter) {
336			return AssertionResult{
337				Type:     "ssl_cert",
338				Expected: "valid cert",
339				Actual:   "expired on " + leaf.NotAfter.Format("2006-01-02"),
340				Passed:   false,
341			}
342		}
343		if check.MinDaysRemaining > 0 {
344			daysLeft := int(leaf.NotAfter.Sub(now).Hours() / 24)
345			if daysLeft < check.MinDaysRemaining {
346				return AssertionResult{
347					Type:     "ssl_cert",
348					Expected: fmt.Sprintf(">= %d days", check.MinDaysRemaining),
349					Actual:   fmt.Sprintf("%d days", daysLeft),
350					Passed:   false,
351				}
352			}
353		}
354		return AssertionResult{
355			Type:     "ssl_cert",
356			Expected: addr,
357			Actual:   fmt.Sprintf("valid, expires %s", leaf.NotAfter.Format("2006-01-02")),
358			Passed:   true,
359		}
360	}
