511	// CheckPostgresPing sends an SSLRequest to a Postgres server and verifies a protocol-valid response.
512	func CheckPostgresPing(check *schema.PostgresCheck) AssertionResult {
513		host := check.Host
514		if host == "" {
515			host = "localhost"
516		}
517		port := check.Port
518		if port == 0 {
519			port = 5432
520		}
521		addr := fmt.Sprintf("%s:%d", host, port)
522		conn, err := net.DialTimeout("tcp", addr, 5*time.Second)
523		if err != nil {
524			return AssertionResult{Type: "postgres_ping", Expected: addr, Actual: err.Error(), Passed: false}
525		}
526		defer conn.Close()
527		conn.SetDeadline(time.Now().Add(5 * time.Second)) //nolint:errcheck
528	
529		// SSLRequest message: int32 length (8), int32 code (80877103)
530		// Bytes: 00 00 00 08 04 D2 16 2F
531		sslReq := []byte{0x00, 0x00, 0x00, 0x08, 0x04, 0xD2, 0x16, 0x2F}
532		if _, err := conn.Write(sslReq); err != nil {
533			return AssertionResult{Type: "postgres_ping", Expected: addr, Actual: "write error: " + err.Error(), Passed: false}
534		}
535		buf := make([]byte, 1)
536		n, err := conn.Read(buf)
537		if err != nil || n == 0 {
538			return AssertionResult{Type: "postgres_ping", Expected: "S or N", Actual: fmt.Sprintf("read error: %v", err), Passed: false}
539		}
540		reply := buf[0]
541		// 'S' = SSL supported, 'N' = SSL not supported, 'E' = error message follows (still valid postgres)
542		if reply == 'S' || reply == 'N' || reply == 'E' {
543			return AssertionResult{Type: "postgres_ping", Expected: addr, Actual: string(reply), Passed: true}
544		}
545		return AssertionResult{Type: "postgres_ping", Expected: "S/N/E", Actual: fmt.Sprintf("0x%02x", reply), Passed: false}
546	}
