548	// CheckMySQLPing verifies a MySQL server sends a valid v10 handshake packet on connection.
549	func CheckMySQLPing(check *schema.MySQLCheck) AssertionResult {
550		host := check.Host
551		if host == "" {
552			host = "localhost"
553		}
554		port := check.Port
555		if port == 0 {
556			port = 3306
557		}
558		addr := fmt.Sprintf("%s:%d", host, port)
559		conn, err := net.DialTimeout("tcp", addr, 5*time.Second)
560		if err != nil {
561			return AssertionResult{Type: "mysql_ping", Expected: addr, Actual: err.Error(), Passed: false}
562		}
563		defer conn.Close()
564		conn.SetDeadline(time.Now().Add(5 * time.Second)) //nolint:errcheck
565	
566		// MySQL server immediately sends a handshake packet:
567		// [3 bytes: payload length][1 byte: sequence id][payload starts with 1 byte: protocol version]
568		// Protocol version 10 (0x0a) is "v10", the current universally-used version.
569		hdr := make([]byte, 5)
570		n, err := conn.Read(hdr)
571		if err != nil || n < 5 {
572			return AssertionResult{Type: "mysql_ping", Expected: "handshake", Actual: fmt.Sprintf("read error: %v (n=%d)", err, n), Passed: false}
573		}
574		protocolVersion := hdr[4]
575		if protocolVersion != 0x0a {
576			return AssertionResult{Type: "mysql_ping", Expected: "protocol v10 (0x0a)", Actual: fmt.Sprintf("0x%02x", protocolVersion), Passed: false}
577		}
578		return AssertionResult{Type: "mysql_ping", Expected: addr, Actual: "v10", Passed: true}
579	}
