584		if timeout == 0 {
585			timeout = 5 * time.Second
586		}
587		ctx, cancel := context.WithTimeout(context.Background(), timeout)
588		defer cancel()
589	
590		var creds credentials.TransportCredentials
591		if check.UseTLS {
592			creds = credentials.NewTLS(nil)
593		} else {
594			creds = insecure.NewCredentials()
595		}
596	
597		conn, err := grpc.NewClient(check.Address, grpc.WithTransportCredentials(creds))
598		if err != nil {
599			return AssertionResult{
600				Type:     "grpc_health",
601				Expected: check.Address,
602				Actual:   "dial error: " + err.Error(),
603				Passed:   false,
604			}
605		}
606		defer conn.Close()
