612				Type:     "grpc_health",
613				Expected: "SERVING",
614				Actual:   "rpc error: " + err.Error(),
615				Passed:   false,
616			}
617		}
618	
619		status := resp.GetStatus().String()
620		return AssertionResult{
621			Type:     "grpc_health",
622			Expected: "SERVING",
623			Actual:   status,
624			Passed:   status == "SERVING",
625		}
