638		defer cancel()
639		out, err := exec.CommandContext(ctx, "docker", "inspect", "--format={{.State.Running}}", check.Name).Output()
640		if err != nil {
641			return AssertionResult{Type: "docker_container_running", Expected: check.Name, Actual: "container not found or docker unavailable: " + err.Error(), Passed: false}
642		}
643		running := strings.TrimSpace(string(out))
644		if running != "true" {
