435				Expected: a.Expected,
436				Actual:   a.Actual,
437				Passed:   a.Passed,
438			})
439		}
440		return reporter.TestResultData{
441			Name:           tr.Name,
442			Passed:         tr.Passed,
443			Skipped:        tr.Skipped,
444			AllowedFailure: tr.AllowedFailure,
445			Duration:       tr.Duration,
446			Assertions:     assertions,
447			Error:          tr.Error,
448		}
449	}
450	
451	func filterTests(tests []schema.Test, include, exclude []string) []schema.Test {
452		if len(include) == 0 && len(exclude) == 0 {
453			return tests
454		}
455	
456		var filtered []schema.Test
457		for _, t := range tests {
458			if len(include) > 0 && !hasAnyTag(t.Tags, include) {
459				continue
460			}
461			if len(exclude) > 0 && hasAnyTag(t.Tags, exclude) {
462				continue
463			}
464			filtered = append(filtered, t)
465		}
466		return filtered
467	}
468	
469	func hasAnyTag(tags, targets []string) bool {
470		for _, tag := range tags {
471			for _, target := range targets {
472				if strings.EqualFold(tag, target) {
473					return true
474				}
475			}
476		}
477		return false
478	}
479	
480	// shouldSkip evaluates skip_if conditions and returns true if the test should be skipped.
481	func shouldSkip(si *schema.SkipIf, configDir string) bool {
482		if si == nil {
483			return false
484		}
485		if si.EnvUnset != "" {
486			if _, ok := os.LookupEnv(si.EnvUnset); !ok {
487				return true
488			}
489		}
490		if si.EnvEquals != nil {
491			if val, ok := os.LookupEnv(si.EnvEquals.Var); ok && val == si.EnvEquals.Value {
492				return true
493			}
494		}
495		if si.FileMissing != "" {
496			path := si.FileMissing
497			if !strings.HasPrefix(path, "/") {
498				path = configDir + "/" + path
499			}
500			if _, err := os.Stat(path); os.IsNotExist(err) {
501				return true
502			}
503		}
504		return false
505	}
