package runner

import (
	"bytes"
	"context"
	"fmt"
	"os"
	"os/exec"
	"strings"
	"sync"
	"time"

	"github.com/CosmoLabs-org/cosmo-smoke/internal/reporter"
	"github.com/CosmoLabs-org/cosmo-smoke/internal/schema"
)

// RunOptions controls test execution behavior.
type RunOptions struct {
	Tags        []string
	ExcludeTags []string
	FailFast    bool
	DryRun      bool
	Timeout     time.Duration // per-test override (0 = use config)
}

// SuiteResult holds the aggregate outcome.
type SuiteResult struct {
	Project         string
	Total           int
	Passed          int
	Failed          int
	Skipped         int
	AllowedFailures int
	Duration        time.Duration
	Tests           []TestResult
}

// TestResult holds one test's outcome.
type TestResult struct {
	Name           string
	Passed         bool
	Skipped        bool
	AllowedFailure bool // true if test failed but allow_failure was set
	Duration       time.Duration
	Assertions     []AssertionResult
	Error          error
	Attempts       int // number of attempts made (1 = no retry)
}

// Runner executes smoke tests from a config.
type Runner struct {
	Config    *schema.SmokeConfig
	Reporter  reporter.Reporter
	ConfigDir string
}

// Run executes all tests per the options and returns the suite result.
func (r *Runner) Run(opts RunOptions) (*SuiteResult, error) {
	start := time.Now()

	// Run prerequisites
	if len(r.Config.Prereqs) > 0 {
		timeout := r.Config.Settings.Timeout.Duration
		if timeout == 0 {
			timeout = 30 * time.Second
		}
		results := CheckPrerequisites(r.Config.Prereqs, timeout)
		for _, pr := range results {
			r.Reporter.PrereqStart(pr.Name)
			r.Reporter.PrereqResult(reporter.PrereqResultData{
				Name:   pr.Name,
				Passed: pr.Passed,
				Output: pr.Output,
				Hint:   pr.Hint,
				Error:  pr.Error,
			})
		}
		// Check for prereq failures
		for _, pr := range results {
			if !pr.Passed {
				return nil, fmt.Errorf("prerequisite %q failed: %v", pr.Name, pr.Error)
			}
		}
	}

	// Filter tests by tags
	tests := filterTests(r.Config.Tests, opts.Tags, opts.ExcludeTags)

	suite := &SuiteResult{
		Project: r.Config.Project,
		Total:   len(tests),
	}

	failFast := opts.FailFast || r.Config.Settings.FailFast

	if r.Config.Settings.Parallel && !failFast {
		r.runParallel(tests, opts, suite)
	} else {
		r.runSequential(tests, opts, suite, failFast)
	}

	suite.Duration = time.Since(start)

	// Report summary
	r.Reporter.Summary(reporter.SuiteResultData{
		Project:         suite.Project,
		Total:           suite.Total,
		Passed:          suite.Passed,
		Failed:          suite.Failed,
		Skipped:         suite.Skipped,
		AllowedFailures: suite.AllowedFailures,
		Duration:        suite.Duration,
	})

	return suite, nil
}

func (r *Runner) runSequential(tests []schema.Test, opts RunOptions, suite *SuiteResult, failFast bool) {
	stopped := false
	for _, t := range tests {
		if stopped {
			tr := TestResult{Name: t.Name, Skipped: true}
			suite.Tests = append(suite.Tests, tr)
			suite.Skipped++
			r.Reporter.TestStart(t.Name)
			r.Reporter.TestResult(reporter.TestResultData{Name: t.Name, Skipped: true})
			continue
		}

		tr := r.runTest(t, opts)
		suite.Tests = append(suite.Tests, tr)
		if tr.Passed {
			suite.Passed++
		} else if tr.Skipped {
			suite.Skipped++
		} else if tr.AllowedFailure {
			suite.AllowedFailures++
		} else {
			suite.Failed++
			if failFast {
				stopped = true
			}
		}
	}
}

func (r *Runner) runParallel(tests []schema.Test, opts RunOptions, suite *SuiteResult) {
	results := make([]TestResult, len(tests))
	var wg sync.WaitGroup

	for i, t := range tests {
		wg.Add(1)
		go func(idx int, test schema.Test) {
			defer wg.Done()
			results[idx] = r.runTest(test, opts)
		}(i, t)
	}
	wg.Wait()

	for _, tr := range results {
		suite.Tests = append(suite.Tests, tr)
		if tr.Passed {
			suite.Passed++
		} else if tr.Skipped {
			suite.Skipped++
		} else if tr.AllowedFailure {
			suite.AllowedFailures++
		} else {
			suite.Failed++
		}
	}
}

func (r *Runner) runTest(t schema.Test, opts RunOptions) TestResult {
	if t.Retry == nil || t.Retry.Count <= 1 {
		res := r.runTestOnce(t, opts)
		if res.Attempts == 0 {
			res.Attempts = 1
		}
		return res
	}
	var last TestResult
	backoff := t.Retry.Backoff.Duration
	for attempt := 1; attempt <= t.Retry.Count; attempt++ {
		last = r.runTestOnce(t, opts)
		if last.Passed {
			last.Attempts = attempt
			return last
		}
		if attempt < t.Retry.Count {
			time.Sleep(backoff)
			backoff *= 2
		}
	}
	last.Attempts = t.Retry.Count
	return last
}

func (r *Runner) runTestOnce(t schema.Test, opts RunOptions) TestResult {
	r.Reporter.TestStart(t.Name)
	start := time.Now()

	// Evaluate skip_if conditions
	if t.SkipIf != nil && shouldSkip(t.SkipIf, r.ConfigDir) {
		tr := TestResult{Name: t.Name, Skipped: true, Duration: time.Since(start)}
		r.Reporter.TestResult(toReporterResult(tr))
		return tr
	}

	if opts.DryRun {
		tr := TestResult{Name: t.Name, Passed: true, Duration: time.Since(start)}
		r.Reporter.TestResult(toReporterResult(tr))
		return tr
	}

	// Determine timeout
	timeout := opts.Timeout
	if timeout == 0 {
		timeout = t.Timeout.Duration
	}
	if timeout == 0 {
		timeout = r.Config.Settings.Timeout.Duration
	}
	if timeout == 0 {
		timeout = 30 * time.Second
	}

	// Run cleanup via defer
	if t.Cleanup != "" {
		defer func() {
			ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
			defer cancel()
			c := exec.CommandContext(ctx, "sh", "-c", t.Cleanup)
			c.Dir = r.ConfigDir
			c.Run()
		}()
	}

	// Execute command
	ctx, cancel := context.WithTimeout(context.Background(), timeout)
	defer cancel()

	cmd := exec.CommandContext(ctx, "sh", "-c", t.Run)
	cmd.Dir = r.ConfigDir
	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	err := cmd.Run()
	exitCode := 0
	if err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			exitCode = exitErr.ExitCode()
		} else {
			tr := TestResult{
				Name:           t.Name,
				AllowedFailure: t.AllowFailure,
				Duration:       time.Since(start),
				Error:          err,
			}
			r.Reporter.TestResult(toReporterResult(tr))
			return tr
		}
	}

	// Evaluate assertions
	var assertions []AssertionResult
	allPassed := true

	if t.Expect.ExitCode != nil {
		a := CheckExitCode(exitCode, *t.Expect.ExitCode)
		assertions = append(assertions, a)
		if !a.Passed {
			allPassed = false
		}
	}
	if t.Expect.StdoutContains != "" {
		a := CheckStdoutContains(stdout.String(), t.Expect.StdoutContains)
		assertions = append(assertions, a)
		if !a.Passed {
			allPassed = false
		}
	}
	if t.Expect.StdoutMatches != "" {
		a := CheckStdoutMatches(stdout.String(), t.Expect.StdoutMatches)
		assertions = append(assertions, a)
		if !a.Passed {
			allPassed = false
		}
	}
	if t.Expect.StderrContains != "" {
		a := CheckStderrContains(stderr.String(), t.Expect.StderrContains)
		assertions = append(assertions, a)
		if !a.Passed {
			allPassed = false
		}
	}
	if t.Expect.StderrMatches != "" {
		a := CheckStderrMatches(stderr.String(), t.Expect.StderrMatches)
		assertions = append(assertions, a)
		if !a.Passed {
			allPassed = false
		}
	}
	if t.Expect.EnvExists != "" {
		a := CheckEnvExists(t.Expect.EnvExists)
		assertions = append(assertions, a)
		if !a.Passed {
			allPassed = false
		}
	}
	if t.Expect.FileExists != "" {
		a := CheckFileExists(t.Expect.FileExists, r.ConfigDir)
		assertions = append(assertions, a)
		if !a.Passed {
			allPassed = false
		}
	}
	if t.Expect.PortListening != nil {
		p := t.Expect.PortListening
		a := CheckPortListening(p.Port, p.Protocol, p.Host)
		assertions = append(assertions, a)
		if !a.Passed {
			allPassed = false
		}
	}
	if t.Expect.ProcessRunning != "" {
		a := CheckProcessRunning(t.Expect.ProcessRunning)
		assertions = append(assertions, a)
		if !a.Passed {
			allPassed = false
		}
	}
	if t.Expect.HTTP != nil {
		httpResults := CheckHTTP(t.Expect.HTTP)
		for _, a := range httpResults {
			assertions = append(assertions, a)
			if !a.Passed {
				allPassed = false
			}
		}
	}
	if t.Expect.JSONField != nil {
		jsonResults := CheckJSONField(stdout.String(), t.Expect.JSONField)
		for _, a := range jsonResults {
			assertions = append(assertions, a)
			if !a.Passed {
				allPassed = false
			}
		}
	}
	if t.Expect.SSLCert != nil {
		a := CheckSSLCert(t.Expect.SSLCert)
		assertions = append(assertions, a)
		if !a.Passed {
			allPassed = false
		}
	}
	if t.Expect.Redis != nil {
		a := CheckRedisPing(t.Expect.Redis)
		assertions = append(assertions, a)
		if !a.Passed {
			allPassed = false
		}
	}
	if t.Expect.Memcached != nil {
		a := CheckMemcachedVersion(t.Expect.Memcached)
		assertions = append(assertions, a)
		if !a.Passed {
			allPassed = false
		}
	}
	if t.Expect.Postgres != nil {
		a := CheckPostgresPing(t.Expect.Postgres)
		assertions = append(assertions, a)
		if !a.Passed {
			allPassed = false
		}
	}
	if t.Expect.MySQL != nil {
		a := CheckMySQLPing(t.Expect.MySQL)
		assertions = append(assertions, a)
		if !a.Passed {
			allPassed = false
		}
	}
	if t.Expect.GRPCHealth != nil {
		a := CheckGRPCHealth(t.Expect.GRPCHealth)
		assertions = append(assertions, a)
		if !a.Passed {
			allPassed = false
		}
	}
	if t.Expect.DockerContainer != nil {
		a := CheckDockerContainerRunning(t.Expect.DockerContainer)
		assertions = append(assertions, a)
		if !a.Passed {
			allPassed = false
		}
	}
	if t.Expect.DockerImage != nil {
		a := CheckDockerImageExists(t.Expect.DockerImage)
		assertions = append(assertions, a)
		if !a.Passed {
			allPassed = false
		}
	}

	duration := time.Since(start)

	if t.Expect.ResponseTimeMs != nil {
		a := CheckResponseTime(int(duration.Milliseconds()), *t.Expect.ResponseTimeMs)
		assertions = append(assertions, a)
		if !a.Passed {
			allPassed = false
		}
	}

	tr := TestResult{
		Name:           t.Name,
		Passed:         allPassed,
		AllowedFailure: !allPassed && t.AllowFailure,
		Duration:       duration,
		Assertions:     assertions,
	}
	r.Reporter.TestResult(toReporterResult(tr))
	return tr
}

func toReporterResult(tr TestResult) reporter.TestResultData {
	var assertions []reporter.AssertionDetail
	for _, a := range tr.Assertions {
		assertions = append(assertions, reporter.AssertionDetail{
			Type:     a.Type,
			Expected: a.Expected,
			Actual:   a.Actual,
			Passed:   a.Passed,
		})
	}
	return reporter.TestResultData{
		Name:           tr.Name,
		Passed:         tr.Passed,
		Skipped:        tr.Skipped,
		AllowedFailure: tr.AllowedFailure,
		Duration:       tr.Duration,
		Assertions:     assertions,
		Error:          tr.Error,
	}
}

func filterTests(tests []schema.Test, include, exclude []string) []schema.Test {
	if len(include) == 0 && len(exclude) == 0 {
		return tests
	}

	var filtered []schema.Test
	for _, t := range tests {
		if len(include) > 0 && !hasAnyTag(t.Tags, include) {
			continue
		}
		if len(exclude) > 0 && hasAnyTag(t.Tags, exclude) {
			continue
		}
		filtered = append(filtered, t)
	}
	return filtered
}

func hasAnyTag(tags, targets []string) bool {
	for _, tag := range tags {
		for _, target := range targets {
			if strings.EqualFold(tag, target) {
				return true
			}
		}
	}
	return false
}

// shouldSkip evaluates skip_if conditions and returns true if the test should be skipped.
func shouldSkip(si *schema.SkipIf, configDir string) bool {
	if si == nil {
		return false
	}
	if si.EnvUnset != "" {
		if _, ok := os.LookupEnv(si.EnvUnset); !ok {
			return true
		}
	}
	if si.EnvEquals != nil {
		if val, ok := os.LookupEnv(si.EnvEquals.Var); ok && val == si.EnvEquals.Value {
			return true
		}
	}
	if si.FileMissing != "" {
		path := si.FileMissing
		if !strings.HasPrefix(path, "/") {
			path = configDir + "/" + path
		}
		if _, err := os.Stat(path); os.IsNotExist(err) {
			return true
		}
	}
	return false
}

package schema

import (
	"bytes"
	"fmt"
	"os"
	"path/filepath"
	"text/template"
	"time"

	"gopkg.in/yaml.v3"
)

// SmokeConfig is the top-level configuration parsed from .smoke.yaml.
type SmokeConfig struct {
	Version     int            `yaml:"version"`
	Project     string         `yaml:"project"`
	Description string         `yaml:"description,omitempty"`
	Includes    []string       `yaml:"includes,omitempty"`
	Settings    Settings       `yaml:"settings,omitempty"`
	Prereqs     []Prerequisite `yaml:"prerequisites,omitempty"`
	Tests       []Test         `yaml:"tests"`
}

// Settings controls global test behavior.
type Settings struct {
	Timeout  Duration `yaml:"timeout,omitempty"`
	FailFast bool     `yaml:"fail_fast,omitempty"`
	Parallel bool     `yaml:"parallel,omitempty"`
}

// Prerequisite is a command that must succeed before tests run.
type Prerequisite struct {
	Name  string `yaml:"name"`
	Check string `yaml:"check"`
	Hint  string `yaml:"hint,omitempty"`
}

// RetryPolicy configures automatic retry for flaky tests.
type RetryPolicy struct {
	Count   int      `yaml:"count"`
	Backoff Duration `yaml:"backoff"`
}

// Test defines a single smoke test.
type Test struct {
	Name         string       `yaml:"name"`
	Run          string       `yaml:"run"`
	Expect       Expect       `yaml:"expect"`
	Tags         []string     `yaml:"tags,omitempty"`
	Timeout      Duration     `yaml:"timeout,omitempty"`
	Cleanup      string       `yaml:"cleanup,omitempty"`
	AllowFailure bool         `yaml:"allow_failure,omitempty"`
	Retry        *RetryPolicy `yaml:"retry,omitempty"`
	SkipIf       *SkipIf      `yaml:"skip_if,omitempty"`
}

// SkipIf defines conditions under which a test should be skipped.
type SkipIf struct {
	EnvUnset  string         `yaml:"env_unset,omitempty"`
	EnvEquals *EnvEqualsCond `yaml:"env_equals,omitempty"`
	FileMissing string       `yaml:"file_missing,omitempty"`
}

// EnvEqualsCond checks if an env var equals a specific value.
type EnvEqualsCond struct {
	Var   string `yaml:"var"`
	Value string `yaml:"value"`
}

// Expect defines the assertions for a test.
type Expect struct {
	ExitCode       *int            `yaml:"exit_code,omitempty"`
	StdoutContains string          `yaml:"stdout_contains,omitempty"`
	StdoutMatches  string          `yaml:"stdout_matches,omitempty"`
	StderrContains string          `yaml:"stderr_contains,omitempty"`
	StderrMatches  string          `yaml:"stderr_matches,omitempty"`
	FileExists     string          `yaml:"file_exists,omitempty"`
	EnvExists      string          `yaml:"env_exists,omitempty"`
	PortListening  *PortCheck      `yaml:"port_listening,omitempty"`
	ProcessRunning string          `yaml:"process_running,omitempty"`
	HTTP           *HTTPCheck      `yaml:"http,omitempty"`
	JSONField      *JSONFieldCheck  `yaml:"json_field,omitempty"`
	ResponseTimeMs *int             `yaml:"response_time_ms,omitempty"` // Fail if test duration exceeds this many ms
	SSLCert        *SSLCertCheck    `yaml:"ssl_cert,omitempty"`
	Redis          *RedisCheck      `yaml:"redis_ping,omitempty"`
	Memcached      *MemcachedCheck  `yaml:"memcached_version,omitempty"`
	Postgres       *PostgresCheck   `yaml:"postgres_ping,omitempty"`
	MySQL          *MySQLCheck      `yaml:"mysql_ping,omitempty"`
	GRPCHealth      *GRPCHealthCheck      `yaml:"grpc_health,omitempty"`
	DockerContainer *DockerContainerCheck `yaml:"docker_container_running,omitempty"`
	DockerImage     *DockerImageCheck     `yaml:"docker_image_exists,omitempty"`
}

// PortCheck defines parameters for checking if a port is open and listening.
type PortCheck struct {
	Port     int    `yaml:"port"`
	Protocol string `yaml:"protocol,omitempty"`
	Host     string `yaml:"host,omitempty"`
}

// SSLCertCheck defines parameters for TLS certificate validation.
type SSLCertCheck struct {
	Host             string `yaml:"host"`
	Port             int    `yaml:"port,omitempty"`               // defaults to 443
	MinDaysRemaining int    `yaml:"min_days_remaining,omitempty"` // 0 = any non-expired cert passes
	AllowSelfSigned  bool   `yaml:"allow_self_signed,omitempty"`
}

// RedisCheck pings a Redis server with PING and verifies PONG reply.
type RedisCheck struct {
	Host     string `yaml:"host,omitempty"`     // default "localhost"
	Port     int    `yaml:"port,omitempty"`     // default 6379
	Password string `yaml:"password,omitempty"` // optional AUTH
}

// MemcachedCheck issues `version` to a Memcached server and expects a VERSION reply.
type MemcachedCheck struct {
	Host string `yaml:"host,omitempty"` // default "localhost"
	Port int    `yaml:"port,omitempty"` // default 11211
}

// PostgresCheck pings a Postgres server via SSLRequest handshake.
type PostgresCheck struct {
	Host string `yaml:"host,omitempty"` // default "localhost"
	Port int    `yaml:"port,omitempty"` // default 5432
}

// MySQLCheck verifies a MySQL server sends a valid handshake on connection.
type MySQLCheck struct {
	Host string `yaml:"host,omitempty"` // default "localhost"
	Port int    `yaml:"port,omitempty"` // default 3306
}

// DockerContainerCheck verifies a named Docker container is running.
type DockerContainerCheck struct {
	Name string `yaml:"name"`
}

// DockerImageCheck verifies a Docker image exists locally.
type DockerImageCheck struct {
	Image string `yaml:"image"`
}

// HTTPCheck defines parameters for HTTP endpoint assertions.
type HTTPCheck struct {
	URL            string            `yaml:"url"`
	Method         string            `yaml:"method,omitempty"`
	Headers        map[string]string `yaml:"headers,omitempty"`
	Body           string            `yaml:"body,omitempty"`
	Timeout        Duration          `yaml:"timeout,omitempty"`
	StatusCode     *int              `yaml:"status_code,omitempty"`
	BodyContains   string            `yaml:"body_contains,omitempty"`
	BodyMatches    string            `yaml:"body_matches,omitempty"`
	HeaderContains map[string]string `yaml:"header_contains,omitempty"`
}

// GRPCHealthCheck queries the grpc.health.v1.Health/Check endpoint.
type GRPCHealthCheck struct {
	Address string   `yaml:"address"`           // host:port
	Service string   `yaml:"service,omitempty"` // "" = overall server health
	UseTLS  bool     `yaml:"use_tls,omitempty"` // default false (insecure)
	Timeout Duration `yaml:"timeout,omitempty"` // default 5s
}

// JSONFieldCheck defines parameters for asserting on JSON fields in stdout.
type JSONFieldCheck struct {
	Path     string `yaml:"path"`
	Equals   string `yaml:"equals,omitempty"`
	Contains string `yaml:"contains,omitempty"`
	Matches  string `yaml:"matches,omitempty"`
}

// Duration wraps time.Duration for YAML unmarshaling from strings like "5s".
type Duration struct {
	time.Duration
}

func (d *Duration) UnmarshalYAML(value *yaml.Node) error {
	var s string
	if err := value.Decode(&s); err != nil {
		return err
	}
	parsed, err := time.ParseDuration(s)
	if err != nil {
		return fmt.Errorf("invalid duration %q: %w", s, err)
	}
	d.Duration = parsed
	return nil
}

func (d Duration) MarshalYAML() (interface{}, error) {
	return d.Duration.String(), nil
}

// Load reads and parses a .smoke.yaml file from the given path.
// Supports Go templates ({{ .Env.FOO }}) and includes.
func Load(path string) (*SmokeConfig, error) {
	return loadWithDepth(path, 0)
}

func loadWithDepth(path string, depth int) (*SmokeConfig, error) {
	if depth > 10 {
		return nil, fmt.Errorf("include depth exceeded (max 10): circular includes?")
	}

	data, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("reading config: %w", err)
	}

	// Process Go templates
	processed, err := processTemplate(data)
	if err != nil {
		return nil, fmt.Errorf("processing template: %w", err)
	}

	cfg, err := Parse(processed)
	if err != nil {
		return nil, err
	}

	// Process includes
	configDir := filepath.Dir(path)
	for _, inc := range cfg.Includes {
		incPath := inc
		if !filepath.IsAbs(inc) {
			incPath = filepath.Join(configDir, inc)
		}

		incCfg, err := loadWithDepth(incPath, depth+1)
		if err != nil {
			return nil, fmt.Errorf("loading include %q: %w", inc, err)
		}

		// Merge: included tests and prereqs are prepended
		cfg.Prereqs = append(incCfg.Prereqs, cfg.Prereqs...)
		cfg.Tests = append(incCfg.Tests, cfg.Tests...)
	}

	return cfg, nil
}

// processTemplate expands Go templates in the config.
// Available: .Env (environment variables map)
func processTemplate(data []byte) ([]byte, error) {
	tmpl, err := template.New("config").Parse(string(data))
	if err != nil {
		return nil, err
	}

	// Build template data
	envMap := make(map[string]string)
	for _, e := range os.Environ() {
		if idx := bytes.IndexByte([]byte(e), '='); idx > 0 {
			envMap[e[:idx]] = e[idx+1:]
		}
	}

	var buf bytes.Buffer
	err = tmpl.Execute(&buf, map[string]any{
		"Env": envMap,
	})
	if err != nil {
		return nil, err
	}

	return buf.Bytes(), nil
}

// Parse parses raw YAML bytes into a SmokeConfig.
func Parse(data []byte) (*SmokeConfig, error) {
	var cfg SmokeConfig
	if err := yaml.Unmarshal(data, &cfg); err != nil {
		return nil, fmt.Errorf("parsing config: %w", err)
	}
	return &cfg, nil
}

// LoadDefault finds and loads .smoke.yaml from the current directory.
func LoadDefault() (*SmokeConfig, error) {
	return Load(".smoke.yaml")
}

// MergeEnv loads an environment-specific config and deep-merges it onto base.
// Env-specific tests are appended (not replaced). Settings from env override base.
func MergeEnv(base *SmokeConfig, envPath string) (*SmokeConfig, error) {
	envCfg, err := Load(envPath)
	if err != nil {
		return nil, fmt.Errorf("loading env config %s: %w", envPath, err)
	}

	// Deep merge: env settings override base
	if envCfg.Settings.Timeout.Duration > 0 {
		base.Settings.Timeout = envCfg.Settings.Timeout
	}
	if envCfg.Settings.FailFast {
		base.Settings.FailFast = true
	}
	if envCfg.Settings.Parallel {
		base.Settings.Parallel = true
	}

	// Prepend env prereqs (they run before base prereqs)
	base.Prereqs = append(envCfg.Prereqs, base.Prereqs...)

	// Append env tests (they run after base tests)
	base.Tests = append(base.Tests, envCfg.Tests...)

	return base, nil
}

