			if e.Bucket == "" {
				errs = append(errs, fmt.Sprintf("%s: s3_bucket.bucket is required", prefix))
			}
		}
		if e := t.Expect.VersionCheck; e != nil {
			if e.Command == "" {
				errs = append(errs, fmt.Sprintf("%s: version_check.command is required", prefix))
