179			}
180			return res
181		}
182		var last TestResult
183		backoff := t.Retry.Backoff.Duration
184		for attempt := 1; attempt <= t.Retry.Count; attempt++ {
185			last = r.runTestOnce(t, opts)
186			if last.Passed {
187				last.Attempts = attempt
188				return last
189			}
190			if attempt < t.Retry.Count {
191				time.Sleep(backoff)
192				backoff *= 2
193			}
194		}
195		last.Attempts = t.Retry.Count
196		return last
197	}
