456		var filtered []schema.Test
457		for _, t := range tests {
458			if len(include) > 0 && !hasAnyTag(t.Tags, include) {
459				continue
460			}
461			if len(exclude) > 0 && hasAnyTag(t.Tags, exclude) {
462				continue
463			}
464			filtered = append(filtered, t)
465		}
466		return filtered
467	}
