482		if si == nil {
483			return false
484		}
485		if si.EnvUnset != "" {
486			if _, ok := os.LookupEnv(si.EnvUnset); !ok {
487				return true
488			}
489		}
490		if si.EnvEquals != nil {
491			if val, ok := os.LookupEnv(si.EnvEquals.Var); ok && val == si.EnvEquals.Value {
492				return true
493			}
494		}
495		if si.FileMissing != "" {
496			path := si.FileMissing
497			if !strings.HasPrefix(path, "/") {
498				path = configDir + "/" + path
499			}
500			if _, err := os.Stat(path); os.IsNotExist(err) {
501				return true
502			}
503		}
504		return false
505	}
